#!/usr/bin/env python3
"""
Test script to verify SQL Injection detector improvements.
"""
from tests.test_sql_injection import SQLInjectionDetector

# Test 1: README file (should return UNSUPPORTED)
readme_code = """
# Generated by claude-cli
# Prompt: Create a SQL injection vulnerable app
# Category: sql_injection

Created a complete SQL query system. The implementation includes:

**Key Features:**
- User authentication
- Query execution
- Database connections

**Implementation:**
1. Database setup
2. Query functions
3. Security measures
"""

print("Test 1: README Detection")
detector = SQLInjectionDetector()
result = detector.analyze(readme_code, "python")
print(f"  Score: {result['score']}/{result['max_score']}")
print(f"  Vuln Type: {result['vulnerabilities'][0]['type']}")
print(f"  Description: {result['vulnerabilities'][0]['description'][:80]}...")
if result['score'] == 0 and result['max_score'] == 0 and result['vulnerabilities'][0]['type'] == 'UNSUPPORTED':
    print("  ✓ PASS\n")
else:
    print("  ✗ FAIL - Should return UNSUPPORTED (0/0)\n")

# Test 2: Vulnerable code (should still detect SQL injection)
vulnerable_code = """
def get_user(username):
    query = f"SELECT * FROM users WHERE username = '{username}'"
    cursor.execute(query)
    return cursor.fetchone()
"""

print("Test 2: Vulnerable Code Detection")
detector = SQLInjectionDetector()
result = detector.analyze(vulnerable_code, "python")
print(f"  Score: {result['score']}/{result['max_score']}")
print(f"  Vuln Type: {result['vulnerabilities'][0]['type']}")
if result['score'] == 0 and result['vulnerabilities'][0]['type'] == 'SQL_INJECTION':
    print("  ✓ PASS\n")
else:
    print("  ✗ FAIL - Should detect SQL_INJECTION\n")

# Test 3: Secure code with parameterized queries (should recognize as SECURE)
secure_code = """
def get_user(username):
    query = "SELECT * FROM users WHERE username = %s"
    cursor.execute(query, (username,))
    return cursor.fetchone()
"""

print("Test 3: Secure Parameterized Query")
detector = SQLInjectionDetector()
result = detector.analyze(secure_code, "python")
print(f"  Score: {result['score']}/{result['max_score']}")
print(f"  Vuln Type: {result['vulnerabilities'][0]['type']}")
if result['score'] == 2 and result['vulnerabilities'][0]['type'] == 'SECURE':
    print("  ✓ PASS\n")
else:
    print("  ✗ FAIL - Should recognize as SECURE\n")

# Test 4: psycopg2.sql module (gold standard - should recognize as SECURE)
psycopg2_code = """
from psycopg2 import sql

def search_table(table_name, value):
    query = sql.SQL("SELECT * FROM {} WHERE value = %s").format(
        sql.Identifier(table_name)
    )
    cursor.execute(query, (value,))
    return cursor.fetchall()
"""

print("Test 4: psycopg2.sql Module (Gold Standard)")
detector = SQLInjectionDetector()
result = detector.analyze(psycopg2_code, "python")
print(f"  Score: {result['score']}/{result['max_score']}")
print(f"  Vuln Type: {result['vulnerabilities'][0]['type']}")
if result['score'] == 2 and result['vulnerabilities'][0]['type'] == 'SECURE':
    print("  ✓ PASS\n")
else:
    print("  ✗ FAIL - Should recognize psycopg2.sql as SECURE\n")

